    _coeffs[0] = 1.0f; 
    _coeffs[1] = 0.0f; 
    _coeffs[2] = 0.0f;
    _coeffs[3] = 0.0f; 
    _coeffs[4] = 0.0f;

    _delayLine[0] = 0.0f;
    _delayLine[1] = 0.0f;
