"#include <Arduino.h>
#include <RadDSP.h>

// Konfigurasi I2S Master
#define I2S_PORT       I2S_NUM_0
#define SAMPLE_RATE    48000
#define BITS_PER_SAMP  32     // PCM1808 adalah 24-bit, menggunakan format I2S standar yang dipad 32-bit di ESP32
#define IS_MASTER      true

#define PIN_BCK        26
#define PIN_WS         25
#define PIN_DIN        23     // Dari DOUT PCM1808 (ADC)
#define PIN_DOUT       33     // Ke DIN Slave ESP32

RadDSP::I2S i2sMaster;

// Buffer untuk DMA dan passthrough (buffer kecil agar latensi rendah)
#define BUFFER_SAMPLES 64 
int32_t audioBuffer[BUFFER_SAMPLES * 2]; // 2 Channel (L/R)

void setup() {
    Serial.begin(115200);
    Serial.println("ESP32 MASTER: I2S Passthrough Started");

    // Inisialisasi I2S Master
    bool success = i2sMaster.begin(I2S_PORT, SAMPLE_RATE, BITS_PER_SAMP, IS_MASTER, PIN_BCK, PIN_WS, PIN_DOUT, PIN_DIN);
    if (success) {
        Serial.println("I2S Master Initialized Successfully.");
    } else {
        Serial.println("I2S Master Initialization Failed!");
    }
