// Konfigurasi I2S Slave
#define I2S_PORT       I2S_NUM_0
#define SAMPLE_RATE    48000
#define BITS_PER_SAMP  32     // Sama dengan Master (32-bit frame untuk PCM1754 24-bit)
#define IS_MASTER      false  // Sebagai SLAVE! Mengikuti clock dari Master

#define PIN_BCK        4      // BCLK dari Master
#define PIN_WS         16     // LRCK dari Master
#define PIN_DIN        17     // Menerima DOUT Master
#define PIN_DOUT       25     // Mengirim ke DIN DAC PCM1754

RadDSP::I2S i2sSlave;

