void setup() {
    Serial.begin(115200);
    Serial.println("ESP32 SLAVE: I2S Passthrough Started");

    // Inisialisasi I2S Slave
    bool success = i2sSlave.begin(I2S_PORT, SAMPLE_RATE, BITS_PER_SAMP, IS_MASTER, PIN_BCK, PIN_WS, PIN_DOUT, PIN_DIN);
    if (success) {
        Serial.println("I2S Slave Initialized Successfully.");
    } else {
        Serial.println("I2S Slave Initialization Failed!");
    }
}

void loop() {
    // Membaca data dari ESP32 Master
    size_t bytesRead = i2sSlave.read((void*)audioBuffer, sizeof(audioBuffer));

    if (bytesRead > 0) {
        // Mengirim data ke DAC PCM1754
        i2sSlave.write((void*)audioBuffer, bytesRead);
    }
}
