"#include <RadDSP.h>

RadDSP::I2S i2s;
RadDSP::Controller dspControl;

// --- EQ PRE (Sebelum Pemrosesan Lainnya) ---
RadDSP::Biquad EqPreBand1;
RadDSP::Biquad EqPreBand2;
RadDSP::Biquad EqPreBand3;
RadDSP::Biquad EqPreBand4;

// --- EQ POST (Setelah Pemrosesan Lainnya) ---
RadDSP::Biquad EqPostBand1;
RadDSP::Biquad EqPostBand2;
RadDSP::Biquad EqPostBand3;
RadDSP::Biquad EqPostBand4;

void audioLoop() {
    if (i2s.readBlock()) {
        float* left = i2s.getLeftBuffer();
        float* right = i2s.getRightBuffer();
        int len = i2s.getBufferLength();

        // 1. PRE-EQ STAGE
        EqPreBand1.process(left, left, len);
        EqPreBand2.process(left, left, len);
        EqPreBand3.process(left, left, len);
        EqPreBand4.process(left, left, len);

        EqPreBand1.process(right, right, len);
        EqPreBand2.process(right, right, len);
        EqPreBand3.process(right, right, len);
        EqPreBand4.process(right, right, len);

        // (Di sini Anda bisa menaruh modul Compressor/Delay dsb)

        // 2. POST-EQ STAGE
        EqPostBand1.process(left, left, len);
        EqPostBand2.process(left, left, len);
        EqPostBand3.process(left, left, len);
        EqPostBand4.process(left, left, len);

        EqPostBand1.process(right, right, len);
        EqPostBand2.process(right, right, len);
        EqPostBand3.process(right, right, len);
        EqPostBand4.process(right, right, len);

        // 3. Output Data
        i2s.writeBlock();
    }
}

void setup() {
    Serial.begin(115200);

    // Mendaftarkan PRE-EQ (ID 1-4)
    dspControl.attach(1, &EqPreBand1);
    dspControl.attach(2, &EqPreBand2);
    dspControl.attach(3, &EqPreBand3);
    dspControl.attach(4, &EqPreBand4);

    // Mendaftarkan POST-EQ (ID 5-8)
    dspControl.attach(5, &EqPostBand1);
    dspControl.attach(6, &EqPostBand2);
    dspControl.attach(7, &EqPostBand3);
    dspControl.attach(8, &EqPostBand4);


