"// ============================================================================
// FUNGSI I2S UTAMA (Core 1)
// ============================================================================
void audioLoop() {
    dspControl.poll();

    if (i2s.readBlock()) {
        float* left = i2s.getLeftBuffer();
        float* right = i2s.getRightBuffer();
        int len = i2s.getBufferLength();

        // FORK-JOIN DENGAN LAMBDA
        dualCore.process(
            // --- TUGAS CORE 1 (KIRI) ---
            [&]() {
                dspControl.markProcessStart(1); 

                left = EqPreBand4.process(EqPreBand3.process(EqPreBand2.process(EqPreBand1.process(left, len, 0), len, 0), len, 0), len, 0);
                left = EqPostBand4.process(EqPostBand3.process(EqPostBand2.process(EqPostBand1.process(left, len, 0), len, 0), len, 0), len, 0);

                dspControl.markProcessEnd(1, len, 48000); 
            },

            // --- TUGAS CORE 0 (KANAN) ---
            [&]() {
                dspControl.markProcessStart(0); 

                right = EqPreBand4.process(EqPreBand3.process(EqPreBand2.process(EqPreBand1.process(right, len, 1), len, 1), len, 1), len, 1);
                right = EqPostBand4.process(EqPostBand3.process(EqPostBand2.process(EqPostBand1.process(right, len, 1), len, 1), len, 1), len, 1);

                dspControl.markProcessEnd(0, len, 48000); 
            }
        );

        i2s.writeBlock();
