+    inline float processSample(float input, uint8_t channel = 0) {
+        float* d = _delayLines[channel];
+        float* c = _activeCoeffs;
+        float y = input * c[0] + d[0] * c[1] + d[1] * c[2] - d[2] * c[3] - d[3] * c[4];
