"#ifndef RAD_MIXER_H
#define RAD_MIXER_H

#include <Arduino.h>
#include "RadControl.h"
#include <math.h>

namespace RadDSP {

    class Mixer2 : public Controllable {
    public:
        Mixer2() : _gain1DB(0.0f), _gain2DB(0.0f), _mul1(1.0f), _mul2(1.0f) {}

        void setParameter(uint8_t paramID, float value) override {
            if (paramID == 0) {
                _gain1DB = value;
                _mul1 = pow(10.0f, _gain1DB / 20.0f);
            } else if (paramID == 1) {
                _gain2DB = value;
                _mul2 = pow(10.0f, _gain2DB / 20.0f);
            }
        }

        float getParameter(uint8_t paramID) override {
            if (paramID == 0) return _gain1DB;
            if (paramID == 1) return _gain2DB;
            return 0.0f;
        }

        #pragma GCC optimize ("O3")
        inline float* process(const float* input1, const float* input2, float* output, int length) {
            // Force local registers for multipliers to ensure FPU accumulation
            register float g1 = _mul1;
            register float g2 = _mul2;
            for (int i = 0; i < length; i++) {
                output[i] = (input1[i] * g1) + (input2[i] * g2);
            }
            return output;
        }

    private:
        float _gain1DB;
        float _gain2DB;
        float _mul1;
        float _mul2;
    };
}

#endif
"

